// Parse the sound director's JSON reply, then normalize and clamp it.
// Robust by design: any parse failure falls back to the user's own words,
// so an empty, garbled, or non-JSON reply still yields a valid request.

const rawMessage = ($('When Chat Message Received').item.json.chatInput || '').toString().trim();

// Basic LLM Chain returns the model text; be liberal about where it sits.
const text = ($json.text ?? $json.response?.text ?? $json.output ?? $json.data ?? '').toString();

let parsed = {};
try {
  // Drop any markdown fences, then grab the first {...} block if prose surrounds it.
  const cleaned = text.replace(/```(?:json)?/gi, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : cleaned);
} catch (e) {
  parsed = {};
}

const clamp = (n, lo, hi) => Math.min(hi, Math.max(lo, n));
const toNum = (v) => {
  const n = typeof v === 'number' ? v : parseFloat(v);
  return Number.isFinite(n) ? n : null;
};

// Prompt: prefer the director's rewrite, fall back to the raw words, then a safe default.
let sfxPrompt = (parsed && typeof parsed.sfx_prompt === 'string') ? parsed.sfx_prompt.trim() : '';
if (!sfxPrompt) sfxPrompt = rawMessage;
if (!sfxPrompt) sfxPrompt = 'a soft, short ambient tone';

// Duration: clamp to the ElevenLabs 0.5-30s window; default 3s if missing.
let duration = toNum(parsed ? parsed.duration_seconds : null);
duration = duration === null ? 3 : Math.round(clamp(duration, 0.5, 30) * 10) / 10;

// Prompt influence: clamp to 0-1; default 0.3 (the ElevenLabs default).
let influence = toNum(parsed ? parsed.prompt_influence : null);
influence = influence === null ? 0.3 : clamp(influence, 0, 1);

return { json: { sfx_prompt: sfxPrompt, duration_seconds: duration, prompt_influence: influence } };

